// 计算需要下载的分段
val pendingSegments = (0 until segmentCount).filter { it !in downloadedSegments }

Log.d("SegmentedDownloader", "Pending segments: ${pendingSegments.size}/${segmentCount}, parallel: ${config.concurrentDownloads}")

// 并行下载分段
kotlinx.coroutines.coroutineScope {
    pendingSegments.chunked(config.concurrentDownloads).forEach { batch ->
        batch.map { i ->
            kotlinx.coroutines.async(Dispatchers.IO) {
                val start = i * segmentSize
                val end = minOf(start + segmentSize - 1, fileSize - 1)

                Log.d("SegmentedDownloader", "Downloading segment $i: $start-$end")

                try {
                    val success = downloadSegment(config.url, tempFile, start, end, config.cookies) { bytes ->
                        val currentTotal = totalDownloaded.addAndGet(bytes)
                        val elapsed = (System.currentTimeMillis() - startTime) / 1000.0
                        val speed = if (elapsed > 0) currentTotal / elapsed.toLong() else 0

                        // 记录速度样本
                        synchronized(speedSamples) {
                            speedSamples.add(speed)
                            if (speedSamples.size > 10) speedSamples.removeAt(0)
                        }

                        // 计算进度
                        val progress = ((currentTotal * 100) / fileSize).toInt().coerceAtMost(99)

                        config.onProgress(DownloadProgress(
                            bytesDownloaded = currentTotal,
                            totalBytes = fileSize,
                            percent = progress,
                            speed = speed,
                            segmentIndex = i + 1,
                            totalSegments = segmentCount,
                            completedSegments = downloadedSegments.toSet(),
                            activeConnections = batch.size
                        ))
                    }

                    if (success) {
                        segmentMutex.lock()
                        try {
                            downloadedSegments.add(i)
                            saveResumeState(tempFile, downloadedSegments)
                        } finally {
                            segmentMutex.unlock()
                        }
                        true
                    } else {
                        Log.w("SegmentedDownloader", "Segment $i download failed after retries")
                        segmentMutex.lock()
                        try {
                            failedSegments.add(i)
                        } finally {
                            segmentMutex.unlock()
                        }
                        false
                    }
                } catch (e: Exception) {
                    Log.e("SegmentedDownloader", "Failed to download segment $i", e)
                    segmentMutex.lock()
                    try {
                        failedSegments.add(i)
                    } finally {
                        segmentMutex.unlock()
                    }
                    false
                }
            }
        }.awaitAll()
    }
}

// 重试失败的分段（串行重试，更稳定）
