                }
            }
            Spacer(Modifier.height(8.dp))

            // 过滤视频列表 - 两个列表不重叠
            val filteredVideos = when (videoListType) {
                0 -> uiState.videos.filter { it.vttPath == null || !File(it.vttPath).exists() }  // 已下载但未转录
                1 -> uiState.videos.filter { it.vttPath != null && File(it.vttPath).exists() }  // 已转录
