@OptIn(ExperimentalFoundationApi::class)
@Composable
private fun VideoListItem(
    video: VideoEntity,
    showTranscribe: Boolean,
    onTranscribe: () -> Unit,
    onPlay: () -> Unit,
    onDelete: () -> Unit,
    onShare: () -> Unit
