        // 移除等待认证的任务
        activeDownloadTasks.entries.find { it.value.status == DownloadStatus.WAITING_FOR_AUTH }?.key?.let { taskId ->
            activeDownloadTasks.remove(taskId)
            updateActiveDownloads()
        }
    }

