    /**
     * 添加到下载队列
     */
    private fun addToQueue(url: String) {
        val task = DownloadTask(
            url = url,
            title = "等待中...",
            status = DownloadStatus.PENDING
        )
        downloadQueue[task.id] = task
        updateQueueList()
    }

    /**
     * 从队列中移除
     */
    private fun removeFromQueue(taskId: String) {
        downloadQueue.remove(taskId)
        updateQueueList()
    }

    /**
     * 更新队列列表
     */
    private fun updateQueueList() {
        _uiState.update { it.copy(downloadQueue = downloadQueue.values.toList()) }
    }

    /**
     * 更新活跃下载列表
     */
    private fun updateActiveDownloads() {
        _uiState.update {
            val activeTasks = activeDownloadTasks.toMap()
            it.copy(
                activeDownloads = activeTasks,
                isProcessing = activeTasks.values.any { task ->
                    task.status == DownloadStatus.FETCHING_INFO || task.status == DownloadStatus.DOWNLOADING
                }
            )
        }
    }

    /**
     * 更新特定下载任务的进度
     */
    private fun updateActiveDownloadTask(taskId: String, task: DownloadTask) {
        activeDownloadTasks[taskId] = task
        updateActiveDownloads()
    }

    /**
     * 下载完成回调
     */
    private fun onDownloadCompleted(taskId: String, task: DownloadTask, file: File, onComplete: (String, String?) -> Unit) {
        viewModelScope.launch(Dispatchers.IO) {
            // 移除活跃任务
            activeDownloadTasks.remove(taskId)
            activeDownloadJobs.remove(taskId)
            updateActiveDownloads()

            // 保存到数据库（移到已下载列表）
            val entity = VideoEntity(
                title = task.title,
                filePath = file.absolutePath,
                vttPath = null,
                language = _uiState.value.selectedLang,
                sourceUrl = task.url
            )
            videoRepository.insert(entity)

            // 添加到历史记录（用于查看下载历史）
            val history = DownloadHistory(
                id = task.id,
                title = task.title,
                url = task.url,
                filePath = file.absolutePath,
                fileSize = file.length(),
                status = DownloadStatus.COMPLETED,
                createdAt = task.createdAt,
                completedAt = task.completedAt
            )
            addToHistory(history)

            withContext(Dispatchers.Main) {
                // 不自动导航到播放器，不自动转录
                // onComplete(file.absolutePath, null)
                // 处理队列中的下一个任务
                processQueue()
            }
        }
    }

    /**
     * 下载失败回调
     */
    private fun onDownloadFailed(taskId: String, task: DownloadTask, error: String) {
        // 移除活跃任务
        activeDownloadTasks.remove(taskId)
        activeDownloadJobs.remove(taskId)
        updateActiveDownloads()

        val failedTask = task.copy(
            status = DownloadStatus.FAILED,
            errorMessage = error
        )
        addToHistory(failedTask)

        // 处理队列中的下一个任务
        processQueue()
    }

    /**
     * 处理下载队列
     */
    private fun processQueue() {
        if (downloadQueue.isEmpty()) return
        if (activeDownloadTasks.size >= MAX_CONCURRENT_DOWNLOADS) return

        // 从队列中取出任务
        val (taskId, task) = downloadQueue.entries.first()
        downloadQueue.remove(taskId)
        updateQueueList()

        // 开始下载
        startDownload(task.url) { _, _ -> }
    }

    /**
     * 添加到历史记录
     */
    private fun addToHistory(task: DownloadTask) {
        val history = DownloadHistory(
            id = task.id,
            title = task.title,
            url = task.url,
            filePath = "", // 下载失败时没有文件路径
            fileSize = task.totalBytes,
            status = task.status,
            createdAt = task.createdAt,
            completedAt = task.completedAt
        )
        val updated = listOf(history) + _downloadHistory.value
        _downloadHistory.update { updated }
        saveDownloadHistory()
    }

    /**
     * 添加成功的历史记录
     */
    private fun addToHistory(history: DownloadHistory) {
        val updated = listOf(history) + _downloadHistory.value
        _downloadHistory.update { updated }
        saveDownloadHistory()
    }

    /**
     * 加载下载历史
     */
    private fun loadDownloadHistory() {
        viewModelScope.launch(Dispatchers.IO) {
            try {
                val historyFile = File(application.filesDir, "download_history.json")
                if (historyFile.exists()) {
                    val json = historyFile.readText()
                    val historyList = Json.decodeFromString<List<DownloadHistory>>(json)
                    _downloadHistory.update { historyList }
                    android.util.Log.d("HomeViewModel", "Loaded download history: ${historyList.size} items")
                }
            } catch (e: Exception) {
                android.util.Log.e("HomeViewModel", "Failed to load download history", e)
            }
        }
    }

    /**
     * 保存下载历史
     */
    private fun saveDownloadHistory() {
        viewModelScope.launch(Dispatchers.IO) {
            try {
                val historyFile = File(application.filesDir, "download_history.json")
                val json = Json.encodeToString(_downloadHistory.value)
                historyFile.writeText(json)
                android.util.Log.d("HomeViewModel", "Saved download history: ${_downloadHistory.value.size} items")
            } catch (e: Exception) {
                android.util.Log.e("HomeViewModel", "Failed to save download history", e)
            }
        }
    }

    /**
     * 格式化文件大小
     */
    fun formatFileSize(bytes: Long): String {
        return when {
            bytes < 1024 -> "$bytes B"
            bytes < 1024 * 1024 -> "${bytes / 1024} KB"
            bytes < 1024 * 1024 * 1024 -> "${bytes / (1024 * 1024)} MB"
            else -> String.format("%.1f GB", bytes / (1024.0 * 1024 * 1024))
        }
    }

    /**
     * 格式化下载速度
     */
    fun formatSpeed(bytesPerSecond: Long): String {
        return when {
            bytesPerSecond < 1024 -> "${bytesPerSecond} B/s"
            bytesPerSecond < 1024 * 1024 -> "${bytesPerSecond / 1024} KB/s"
            else -> String.format("%.1f MB/s", bytesPerSecond / (1024.0 * 1024))
        }
    }

    /**
     * 格式化剩余时间
     */
    fun formatRemainingTime(seconds: Long): String {
        return when {
            seconds < 60 -> "${seconds}秒"
            seconds < 3600 -> "${seconds / 60}分${seconds % 60}秒"
            else -> "${seconds / 3600}小时${(seconds % 3600) / 60}分"
        }
    }

    /**
     * 获取状态文本
     */
    fun getStatusText(status: DownloadStatus): String {
        return when (status) {
            DownloadStatus.PENDING -> "等待中"
            DownloadStatus.FETCHING_INFO -> "解析中..."
            DownloadStatus.DOWNLOADING -> "下载中"
            DownloadStatus.PAUSED -> "已暂停"
            DownloadStatus.COMPLETED -> "已完成"
            DownloadStatus.FAILED -> "失败"
            DownloadStatus.CANCELLED -> "已取消"
            DownloadStatus.WAITING_FOR_AUTH -> "需要登录"
        }
    }

    fun importVideo(context: Context, uri: Uri, onComplete: (String, String?) -> Unit) {
        viewModelScope.launch(Dispatchers.IO) {
            try {
                _uiState.update { it.copy(isProcessing = true) }

                val fileName = getFileName(context, uri) ?: "import_${System.currentTimeMillis()}.mp4"
                android.util.Log.d("HomeViewModel", "Import video fileName: $fileName")

                val tempFile = File(downloadsDir, fileName)

                // 使用原始文件名（不含扩展名）作为标题，而不是时间戳格式
                val displayName = if (fileName.startsWith("import_")) {
                    // 如果是默认文件名，尝试从 Uri 获取更友好的名称
                    val lastPath = uri.lastPathSegment ?: "导入视频"
                    lastPath.substringBeforeLast(".")
                } else {
                    // 使用原始文件名（去掉扩展名）
                    fileName.substringBeforeLast(".")
                }

                android.util.Log.d("HomeViewModel", "Import video displayName: $displayName")

                val inputStream = context.contentResolver.openInputStream(uri)
                val outputStream = FileOutputStream(tempFile)

                inputStream?.use { input ->
                    outputStream.use { output ->
                        input.copyTo(output)
                    }
                }

                val entity = VideoEntity(
                    title = displayName,
                    filePath = tempFile.absolutePath,
                    vttPath = null,
                    language = _uiState.value.selectedLang,
                    sourceUrl = null
                )
                videoRepository.insert(entity)

                // 添加到历史记录
                val history = DownloadHistory(
                    id = UUID.randomUUID().toString(),
                    title = displayName,
                    url = "导入文件",
                    filePath = tempFile.absolutePath,
                    fileSize = tempFile.length(),
                    status = DownloadStatus.COMPLETED,
                    createdAt = System.currentTimeMillis(),
                    completedAt = System.currentTimeMillis()
                )
                addToHistory(history)

                _uiState.update { it.copy(isProcessing = false) }
                launch(Dispatchers.Main) { onComplete(tempFile.absolutePath, null) }
            } catch (e: Exception) {
                android.util.Log.e("MultiLangLearner", "Import failed", e)
                _uiState.update { it.copy(isProcessing = false) }
            }
        }
    }

    private fun getFileName(context: Context, uri: Uri): String? {
        var result: String? = null
        if (uri.scheme == "content") {
            val cursor = context.contentResolver.query(uri, null, null, null, null)
            cursor?.use {
                if (it.moveToFirst()) {
                    val index = it.getColumnIndex(android.provider.OpenableColumns.DISPLAY_NAME)
                    if (index >= 0) result = it.getString(index)
                }
            }
        }
        if (result == null) {
            result = uri.path
            val cut = result?.lastIndexOf('/')
            if (cut != -1) {
                result = result?.substring(cut!! + 1)
            }
        }
        return result
    }

    /**
     * 处理B站Cookie获取完成
     * 保存Cookie并继续待处理的下载
     */
    fun onBilibiliCookiesExtracted(
        sessdata: String?,
        biliJct: String?,
        dedeUserID: String?,
        fullCookie: String = "",
        onComplete: (String, String?) -> Unit
    ) {
        viewModelScope.launch {
            // 优先使用完整Cookie，否则构建基本Cookie
            val cookieString = if (fullCookie.isNotBlank()) {
                fullCookie
            } else {
                buildString {
                    sessdata?.let { append("SESSDATA=$it; ") }
                    biliJct?.let { append("bili_jct=$it; ") }
                    dedeUserID?.let { append("DedeUserID=$it; ") }
                }.trimEnd(' ', ';')
            }

            // 保存Cookie到配置
            if (sessdata != null) {
                videoConfigStore.setBilibiliSessdata(sessdata)
            }
            if (biliJct != null) {
                videoConfigStore.setBilibiliBiliJct(biliJct)
            }
            if (dedeUserID != null) {
                videoConfigStore.setBilibiliDedeuserid(dedeUserID)
            }

            // 立即更新当前Cookie变量（使用完整Cookie）
            if (cookieString.isNotBlank()) {
                currentBilibiliCookie = cookieString
                Log.d("HomeViewModel", "Updated Bilibili cookie, length: ${cookieString.length}")
            }

            // 关闭登录对话框
            _uiState.update { it.copy(showBilibiliLogin = false) }

            // 如果有待处理的URL，继续下载
            val pendingUrl = _uiState.value.pendingDownloadUrl
            if (pendingUrl.isNotBlank()) {
                // 清除待处理URL
                _uiState.update { it.copy(pendingDownloadUrl = "") }

                // 继续下载
                downloadVideo(onComplete)
            }
        }
    }

    /**
     * 取消登录对话框
     */
    fun dismissBilibiliLogin() {
        _uiState.update {
            it.copy(
                showBilibiliLogin = false,
                pendingDownloadUrl = ""
            )
        }
        // 移除等待认证的任务
        activeDownloadTasks.entries.find { it.value.status == DownloadStatus.WAITING_FOR_AUTH }?.key?.let { taskId ->
            activeDownloadTasks.remove(taskId)
            updateActiveDownloads()
        }
    }

