                        selected = videoListType == 0,
                        onClick = { videoListType = 0 },
                        label = { Text("下载中") },
                        leadingIcon = { if (videoListType == 0) Icon(Icons.Default.Check, null, Modifier.size(14.dp)) else null }
                    )
                    FilterChip(
                        selected = videoListType == 1,
                        onClick = { videoListType = 1 },
                        label = { Text("已下载") },
                        leadingIcon = { if (videoListType == 1) Icon(Icons.Default.Check, null, Modifier.size(14.dp)) else null }
                    )
                    FilterChip(
                        selected = videoListType == 2,
                        onClick = { videoListType = 2 },
                        label = { Text("已转录") },
                        leadingIcon = { if (videoListType == 2) Icon(Icons.Default.Check, null, Modifier.size(14.dp)) else null }
                    )
                }
            }
            Spacer(Modifier.height(8.dp))

            // 根据类型显示不同内容
            when (videoListType) {
                0 -> {
                    // 下载中列表 - 显示正在下载的任务
                    if (uiState.activeDownloads.isEmpty()) {
                        Box(Modifier.fillMaxWidth().padding(32.dp), contentAlignment = Alignment.Center) {
                            Text("暂无下载任务\n粘贴链接开始下载", color = MaterialTheme.colorScheme.onSurfaceVariant)
                        }
                    } else {
                        LazyColumn(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                            items(uiState.activeDownloads.values.toList()) { task ->
                                DownloadProgressCard(
                                    task = task,
                                    onCancel = { viewModel.cancelDownload(task.id) },
                                    formatFileSize = { viewModel.formatFileSize(it) },
                                    formatSpeed = { viewModel.formatSpeed(it) },
                                    formatRemainingTime = { viewModel.formatRemainingTime(it) },
