/**
 * 视频列表项组件
 * @param showTranscribe 是否显示转录按钮（已下载但未转录的视频）
 * @param isTranscribed 是否已转录（已转录的视频删除按钮只在对话框中显示）
 */
@Composable
private fun VideoListItem(
    video: VideoEntity,
    showTranscribe: Boolean,
    isTranscribed: Boolean = false,
    onTranscribe: () -> Unit,
    onPlay: () -> Unit,
    onDelete: () -> Unit,
    onShare: () -> Unit,
    onOpenFolder: () -> Unit
) {
    var showActionDialog by remember { mutableStateOf(false) }

    Card(
        modifier = Modifier
            .fillMaxWidth()
            .clickable { showActionDialog = true }
    ) {
        Column(modifier = Modifier.padding(12.dp)) {
            Row(
                verticalAlignment = Alignment.CenterVertically
            ) {
                Icon(
                    Icons.Default.VideoLibrary,
                    contentDescription = null,
                    tint = MaterialTheme.colorScheme.primary
                )
                Spacer(Modifier.width(12.dp))
                Column(Modifier.weight(1f)) {
                    Text(
                        video.title,
                        style = MaterialTheme.typography.bodyLarge,
                        maxLines = 2
                    )
                    Text(
                        if (isTranscribed) "已转录" else "待转录",
                        style = MaterialTheme.typography.bodySmall,
                        color = if (isTranscribed)
                            MaterialTheme.colorScheme.primary
                        else
                            MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
            }

            Spacer(Modifier.height(8.dp))

            // 操作按钮行
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.End
            ) {
                if (showTranscribe) {
                    Button(
                        onClick = onTranscribe,
                        modifier = Modifier.height(36.dp)
                    ) {
                        Icon(Icons.Default.Mic, null, modifier = Modifier.size(16.dp))
                        Spacer(Modifier.width(4.dp))
                        Text("转录")
                    }
                    Spacer(Modifier.width(8.dp))
                }
                OutlinedButton(
                    onClick = onPlay,
                    modifier = Modifier.height(36.dp)
                ) {
                    Icon(Icons.Default.PlayArrow, null, modifier = Modifier.size(16.dp))
                    Spacer(Modifier.width(4.dp))
                    Text("播放")
                }
            }
        }
    }

    // 点击操作对话框
    if (showActionDialog) {
        AlertDialog(
            onDismissRequest = { showActionDialog = false },
            title = { Text(video.title) },
            text = {
                Column(
                    modifier = Modifier.fillMaxWidth(),
                    verticalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    // 打开所在文件夹
                    OutlinedButton(
                        onClick = {
                            showActionDialog = false
                            onOpenFolder()
                        },
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        Icon(Icons.Default.Folder, null, modifier = Modifier.size(18.dp))
                        Spacer(Modifier.width(8.dp))
                        Text("打开所在文件夹")
                    }
                    // 分享
                    OutlinedButton(
                        onClick = {
                            showActionDialog = false
                            onShare()
                        },
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        Icon(Icons.Default.Share, null, modifier = Modifier.size(18.dp))
                        Spacer(Modifier.width(8.dp))
                        Text("分享到微信")
                    }
                    // 删除
                    OutlinedButton(
                        onClick = {
                            showActionDialog = false
                            onDelete()
                        },
                        modifier = Modifier.fillMaxWidth(),
                        colors = ButtonDefaults.outlinedButtonColors(
                            contentColor = MaterialTheme.colorScheme.error
                        )
                    ) {
                        Icon(Icons.Default.Delete, null, modifier = Modifier.size(18.dp))
                        Spacer(Modifier.width(8.dp))
                        Text("删除视频")
                    }
                }
            },
            confirmButton = {
                TextButton(onClick = { showActionDialog = false }) {
                    Text("取消")
                }
            }
        )
    }
}

