/**
 * 打开应用文件夹（视频下载目录）
 */
fun openFileLocation(filePath: String, context: Context) {
    viewModelScope.launch(Dispatchers.IO) {
        try {
            // 打开应用的视频下载目录
            val videosDir = downloadsDir

            if (!videosDir.exists()) {
                videosDir.mkdirs()
            }

            android.util.Log.d("HomeViewModel", "Opening folder: ${videosDir.absolutePath}")

            // 使用 Intent 打开文件管理器
            val intent = Intent(Intent.ACTION_VIEW).apply {
                val uri = androidx.core.content.FileProvider.getUriForFile(
                    context,
                    "${context.packageName}.fileprovider",
                    videosDir
                )
                setDataAndType(uri, "resource/folder")
                addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)
                addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
            }

            try {
                context.startActivity(intent)
            } catch (e: Exception) {
                android.util.Log.w("HomeViewModel", "Failed to open folder with file manager", e)
                // 如果失败，尝试使用 ACTION_OPEN_DOCUMENT
                val fallbackIntent = Intent(Intent.ACTION_OPEN_DOCUMENT).apply {
                    addCategory(Intent.CATEGORY_OPENABLE)
                    type = "*/*"
                    putExtra(DocumentsContract.EXTRA_INITIAL_URI,
                        androidx.core.content.FileProvider.getUriForFile(
                            context,
                            "${context.packageName}.fileprovider",
                            videosDir
                        )
                    )
                }
                context.startActivity(fallbackIntent)
            }

            withContext(Dispatchers.Main) {
                android.widget.Toast.makeText(
                    context,
                    "文件夹: ${videosDir.absolutePath}",
                    android.widget.Toast.LENGTH_SHORT
                ).show()
            }
        } catch (e: Exception) {
            android.util.Log.e("HomeViewModel", "Error opening folder", e)
            withContext(Dispatchers.Main) {
                android.widget.Toast.makeText(
                    context,
                    "无法打开文件夹: ${e.message}",
                    android.widget.Toast.LENGTH_LONG
                ).show()
            }
        }
    }
}

